     1→import {
     2→	AlertTriangle,
     3→	Building2,
     4→	Check,
     5→	Copy,
     6→	Loader2,
     7→	Mail,
     8→	Pencil,
     9→	Plus,
    10→	Trash2,
    11→	UserPlus,
    12→	X,
    13→} from "lucide-react";
    14→import { useRef, useState } from "react";
    15→import { Link, useNavigate } from "react-router-dom";
    16→import { AnalyticsCard } from "../../components/analytics/AnalyticsCard";
    17→import { PageHeader } from "../../components/analytics/PageHeader";
    18→import { DeleteOrganizationDialog } from "../../components/DeleteOrganizationDialog";
    19→import { Badge } from "../../components/ui/badge";
    20→import { Button } from "../../components/ui/button";
    21→import { Input } from "../../components/ui/input";
    22→import { Label } from "../../components/ui/label";
    23→import {
    24→	Select,
    25→	SelectContent,
    26→	SelectItem,
    27→	SelectTrigger,
    28→	SelectValue,
    29→} from "../../components/ui/select";
    30→import { useOrganization } from "../../contexts/OrganizationContext";
    31→import { useFullOrganization } from "../../hooks/useFullOrganization";
    32→import { authClient } from "../../lib/auth-client";
    33→
    34→export function OrganizationPage() {
    35→	const { activeOrg, organizations, switchOrg } = useOrganization();
    36→	const { data: session } = authClient.useSession();
    37→	const navigate = useNavigate();
    38→	const {
    39→		data: fullOrg,
    40→		isLoading: loading,
    41→		invalidate,
    42→	} = useFullOrganization(activeOrg?.id);
    43→	const [inviteEmail, setInviteEmail] = useState("");
    44→	const [inviteRole, setInviteRole] = useState("member");
    45→	const [inviting, setInviting] = useState(false);
    46→	const [inviteLink, setInviteLink] = useState<string | null>(null);
    47→	const [copied, setCopied] = useState(false);
    48→	const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
    49→	const [editing, setEditing] = useState(false);
    50→	const [editName, setEditName] = useState("");
    51→	const [saving, setSaving] = useState(false);
    52→	const [renameError, setRenameError] = useState<string | null>(null);
    53→	const nameInputRef = useRef<HTMLInputElement>(null);
    54→
    55→	const currentUserRole = fullOrg?.members.find(
    56→		(m) => m.userId === session?.user.id,
    57→	)?.role;
    58→	const canEdit = currentUserRole === "owner" || currentUserRole === "admin";
    59→
    60→	const handleStartEditing = () => {
    61→		if (!activeOrg) return;
    62→		setEditName(activeOrg.name);
    63→		setRenameError(null);
    64→		setEditing(true);
    65→		setTimeout(() => nameInputRef.current?.focus(), 0);
    66→	};
    67→
    68→	const handleCancelEditing = () => {
    69→		setEditing(false);
    70→		setRenameError(null);
    71→	};
    72→
    73→	const handleSaveName = async () => {
    74→		const trimmed = editName.trim();
    75→		if (!trimmed || !activeOrg) return;
    76→		if (trimmed === activeOrg.name) {
    77→			setEditing(false);
    78→			return;
    79→		}
    80→
    81→		setSaving(true);
    82→		setRenameError(null);
    83→		const res = await authClient.organization.update({
    84→			data: { name: trimmed },
    85→			organizationId: activeOrg.id,
    86→		});
    87→
    88→		if (res.error) {
    89→			setRenameError(res.error.message ?? "Failed to rename organization");
    90→			setSaving(false);
    91→			return;
    92→		}
    93→
    94→		setEditing(false);
    95→		setSaving(false);
    96→		invalidate();
    97→	};
    98→
    99→	const handleInvite = async (e: React.FormEvent) => {
   100→		e.preventDefault();
   101→		if (!inviteEmail.trim()) return;
   102→		setInviting(true);
   103→		const res = await authClient.organization.inviteMember({
   104→			email: inviteEmail.trim(),
   105→			role: inviteRole as "member" | "admin",
   106→		});
   107→		if (res.data) {
   108→			const link = `${window.location.origin}/invitation/${res.data.id}`;
   109→			setInviteLink(link);
   110→			setInviteEmail("");
   111→			invalidate();
   112→		}
   113→		setInviting(false);
   114→	};
   115→
   116→	const handleCopyLink = () => {
   117→		if (!inviteLink) return;
   118→		navigator.clipboard.writeText(inviteLink);
   119→		setCopied(true);
   120→		setTimeout(() => setCopied(false), 2000);
   121→	};
   122→
   123→	const handleRemoveMember = async (memberIdOrEmail: string) => {
   124→		await authClient.organization.removeMember({ memberIdOrEmail });
   125→		invalidate();
   126→	};
   127→
   128→	const handleCancelInvitation = async (invitationId: string) => {
   129→		await authClient.organization.cancelInvitation({ invitationId });
   130→		invalidate();
   131→	};
   132→
   133→	if (!activeOrg) {
   134→		return (
   135→			<div className="px-8 py-6">
   136→				<p className="text-muted">No organization selected.</p>
   137→			</div>
   138→		);
   139→	}
   140→
   141→	return (
   142→		<div className="px-8 py-6">
   143→			<PageHeader
   144→				title="Organization"
   145→				description={`Manage ${activeOrg.name}`}
   146→				actions={
   147→					<Link to="/dashboard/organization/new">
   148→						<Button size="sm">
   149→							<Plus className="h-4 w-4 mr-1" />
   150→							Create Organization
   151→						</Button>
   152→					</Link>
   153→				}
   154→			/>
   155→
   156→			<div className="flex flex-col gap-6">
   157→				{/* Organization Info */}
   158→				<AnalyticsCard>
   159→					<div className="flex items-center gap-4">
   160→						<div className="flex h-12 w-12 items-center justify-center rounded-lg bg-hover">
   161→							<Building2 className="h-6 w-6 text-muted" />
   162→						</div>
   163→						{editing ? (
   164→							<div className="flex-1">
   165→								<Label htmlFor="org-name">Organization name</Label>
   166→								<div className="flex items-center gap-2 mt-1">
   167→									<Input
   168→										ref={nameInputRef}
   169→										id="org-name"
   170→										value={editName}
   171→										onChange={(e) => setEditName(e.target.value)}
   172→										onKeyDown={(e) => {
   173→											if (e.key === "Enter") handleSaveName();
   174→											if (e.key === "Escape") handleCancelEditing();
   175→										}}
   176→										disabled={saving}
   177→										className="max-w-xs"
   178→									/>
   179→									<Button
   180→										size="sm"
   181→										onClick={handleSaveName}
   182→										disabled={saving || !editName.trim()}
   183→									>
   184→										{saving ? (
   185→											<Loader2 className="h-4 w-4 animate-spin" />
   186→										) : (
   187→											<Check className="h-4 w-4" />
   188→										)}
   189→									</Button>
   190→									<Button
   191→										variant="outline"
   192→										size="sm"
   193→										onClick={handleCancelEditing}
   194→										disabled={saving}
   195→									>
   196→										<X className="h-4 w-4" />
   197→									</Button>
   198→								</div>
   199→								{renameError && (
   200→									<p className="mt-1 text-sm text-red-500">{renameError}</p>
   201→								)}
   202→							</div>
   203→						) : (
   204→							<div className="flex items-center gap-2">
   205→								<div>
   206→									<h2 className="text-lg font-semibold text-heading">
   207→										{activeOrg.name}
   208→									</h2>
   209→									<p className="text-sm text-muted">/{activeOrg.slug}</p>
   210→								</div>
   211→								{canEdit && (
   212→									<Button
   213→										variant="outline"
   214→										size="xs"
   215→										onClick={handleStartEditing}
   216→									>
   217→										<Pencil className="h-3.5 w-3.5" />
   218→									</Button>
   219→								)}
   220→							</div>
   221→						)}
   222→					</div>
   223→				</AnalyticsCard>
   224→
   225→				{/* Invite Members */}
   226→				<AnalyticsCard>
   227→					<h2 className="text-lg font-semibold text-heading mb-4">
   228→						<UserPlus className="h-5 w-5 inline-block mr-2 -mt-0.5" />
   229→						Invite Members
   230→					</h2>
   231→
   232→					<form onSubmit={handleInvite} className="flex gap-2 mb-3">
   233→						<Input
   234→							type="email"
   235→							placeholder="Email address"
   236→							value={inviteEmail}
   237→							onChange={(e) => {
   238→								setInviteEmail(e.target.value);
   239→								if (inviteLink) setInviteLink(null);
   240→							}}
   241→							className="flex-1"
   242→						/>
   243→						<Select value={inviteRole} onValueChange={setInviteRole}>
   244→							<SelectTrigger className="w-auto">
   245→								<SelectValue />
   246→							</SelectTrigger>
   247→							<SelectContent>
   248→								<SelectItem value="member">Member</SelectItem>
   249→								<SelectItem value="admin">Admin</SelectItem>
   250→							</SelectContent>
   251→						</Select>
   252→						<Button
   253→							type="submit"
   254→							size="sm"
   255→							disabled={inviting || !inviteEmail.trim()}
   256→						>
   257→							{inviting ? (
   258→								<Loader2 className="h-4 w-4 animate-spin" />
   259→							) : (
   260→								<Mail className="h-4 w-4 mr-1" />
   261→							)}
   262→							Invite
   263→						</Button>
   264→					</form>
   265→
   266→					{inviteLink && (
   267→						<div className="flex items-center gap-2 rounded-lg border border-border bg-hover/50 px-3 py-2 text-sm">
   268→							<span className="flex-1 truncate text-muted">{inviteLink}</span>
   269→							<Button variant="outline" size="xs" onClick={handleCopyLink}>
   270→								{copied ? (
   271→									<Check className="h-3.5 w-3.5 text-status-success-icon" />
   272→								) : (
   273→									<Copy className="h-3.5 w-3.5" />
   274→								)}
   275→							</Button>
   276→							<Button
   277→								variant="outline"
   278→								size="xs"
   279→								onClick={() => setInviteLink(null)}
   280→							>
   281→								<X className="h-3.5 w-3.5" />
   282→							</Button>
   283→						</div>
   284→					)}
   285→				</AnalyticsCard>
   286→
   287→				{/* Members */}
   288→				<AnalyticsCard>
   289→					<h2 className="text-lg font-semibold text-heading mb-4">Members</h2>
   290→
   291→					{loading ? (
   292→						<p className="text-sm text-muted">Loading...</p>
   293→					) : (
   294→						<div className="flex flex-col gap-2">
   295→							{fullOrg?.members.map((m) => (
   296→								<div
   297→									key={m.id}
   298→									className="flex items-center justify-between rounded-lg border border-border px-4 py-3"
   299→								>
   300→									<div className="flex items-center gap-3">
   301→										{m.user.image ? (
   302→											<img
   303→												src={m.user.image}
   304→												alt=""
   305→												className="h-8 w-8 rounded-full"
   306→											/>
   307→										) : (
   308→											<div className="flex h-8 w-8 items-center justify-center rounded-full bg-hover text-xs font-medium text-muted">
   309→												{m.user.name.charAt(0).toUpperCase()}
   310→											</div>
   311→										)}
   312→										<div>
   313→											<p className="text-sm font-medium text-foreground">
   314→												{m.user.name}
   315→											</p>
   316→											<p className="text-xs text-muted">{m.user.email}</p>
   317→										</div>
   318→									</div>
   319→									<div className="flex items-center gap-2">
   320→										<Badge
   321→											variant={m.role === "owner" ? "default" : "secondary"}
   322→										>
   323→											{m.role}
   324→										</Badge>
   325→										{m.role !== "owner" && (
   326→											<Button
   327→												variant="outline"
   328→												size="xs"
   329→												onClick={() => handleRemoveMember(m.id)}
   330→											>
   331→												<Trash2 className="h-3.5 w-3.5" />
   332→											</Button>
   333→										)}
   334→									</div>
   335→								</div>
   336→							))}
   337→						</div>
   338→					)}
   339→				</AnalyticsCard>
   340→
   341→				{/* Pending Invitations */}
   342→				{fullOrg && fullOrg.invitations.length > 0 && (
   343→					<AnalyticsCard>
   344→						<h2 className="text-lg font-semibold text-heading mb-4">
   345→							Pending Invitations
   346→						</h2>
   347→
   348→						<div className="flex flex-col gap-2">
   349→							{fullOrg.invitations
   350→								.filter((inv) => inv.status === "pending")
   351→								.map((inv) => (
   352→									<div
   353→										key={inv.id}
   354→										className="flex items-center justify-between rounded-lg border border-border px-4 py-3"
   355→									>
   356→										<div className="flex items-center gap-3">
   357→											<Mail className="h-4 w-4 text-muted" />
   358→											<span className="text-sm text-foreground">
   359→												{inv.email}
   360→											</span>
   361→											{inv.role && (
   362→												<Badge variant="secondary">{inv.role}</Badge>
   363→											)}
   364→										</div>
   365→										<Button
   366→											variant="outline"
   367→											size="xs"
   368→											onClick={() => handleCancelInvitation(inv.id)}
   369→										>
   370→											<X className="h-3.5 w-3.5 mr-1" />
   371→											Cancel
   372→										</Button>
   373→									</div>
   374→								))}
   375→						</div>
   376→					</AnalyticsCard>
   377→				)}
   378→
   379→				{/* Danger Zone */}
   380→				<AnalyticsCard className="border-red-500/30">
   381→					<h2 className="text-lg font-semibold text-red-500 mb-2">
   382→						<AlertTriangle className="h-5 w-5 inline-block mr-2 -mt-0.5" />
   383→						Danger Zone
   384→					</h2>
