     1→import { getLogger } from "@logtape/logtape";
     2→import * as schema from "@rudel/sql-schema";
     3→import { betterAuth } from "better-auth";
     4→import { drizzleAdapter } from "better-auth/adapters/drizzle";
     5→import { bearer, organization } from "better-auth/plugins";
     6→import { fetchGitHubHandle, notifySignup } from "./slack.js";
     7→
     8→const logger = getLogger(["rudel", "api", "auth"]);
     9→
    10→export interface AuthConfig {
    11→	appURL: string;
    12→	secret?: string;
    13→	socialProviders?: Record<string, { clientId: string; clientSecret: string }>;
    14→	trustedOrigins?: string[];
    15→	slackWebhookUrl?: string;
    16→}
    17→
    18→// eslint-disable-next-line @typescript-eslint/no-explicit-any -- drizzleAdapter accepts { [key: string]: any }
    19→export function createAuth(db: object, config: AuthConfig) {
    20→	const trustedOrigins = config.trustedOrigins ?? [];
    21→	if (!trustedOrigins.includes(config.appURL)) {
    22→		trustedOrigins.push(config.appURL);
    23→	}
    24→
    25→	return betterAuth({
    26→		baseURL: config.appURL,
    27→		secret: config.secret,
    28→		database: drizzleAdapter(db as Parameters<typeof drizzleAdapter>[0], {
    29→			provider: "pg",
    30→			schema,
    31→		}),
    32→		emailAndPassword: {
    33→			enabled: true,
    34→		},
    35→		socialProviders: config.socialProviders,
    36→		plugins: [
    37→			bearer(),
    38→			organization({
    39→				allowUserToCreateOrganization: true,
    40→				creatorRole: "owner",
    41→			}),
    42→		],
    43→		session: {
    44→			expiresIn: 60 * 60 * 24 * 365,
    45→		},
    46→		trustedOrigins,
    47→		databaseHooks: {
    48→			user: {
    49→				create: {
    50→					after: async (user, ctx) => {
    51→						try {
    52→							const adapter = ctx?.context?.adapter;
    53→							if (!adapter) return;
    54→
    55→							const slug = `${user.email.split("@")[0]}-${user.id.slice(0, 8)}`;
    56→							const org = await adapter.create({
    57→								model: "organization",
    58→								data: {
    59→									id: user.id,
    60→									name: `${user.name}'s Workspace`,
    61→									slug,
    62→									createdAt: new Date(),
    63→								},
    64→								forceAllowId: true,
    65→							});
    66→
    67→							if (org) {
    68→								await adapter.create({
    69→									model: "member",
    70→									data: {
    71→										organizationId: org.id,
    72→										userId: user.id,
    73→										role: "owner",
    74→										createdAt: new Date(),
    75→									},
    76→								});
    77→							}
    78→
    79→							if (config.slackWebhookUrl) {
    80→								let githubHandle: string | null = null;
    81→								const accounts = (await adapter.findMany({
    82→									model: "account",
    83→									where: [{ field: "userId", value: user.id }],
    84→								})) as Array<{ providerId: string; accountId: string }>;
    85→								const githubAccount = accounts.find(
    86→									(a) => a.providerId === "github",
    87→								);
    88→								if (githubAccount) {
    89→									githubHandle = await fetchGitHubHandle(
    90→										githubAccount.accountId,
    91→									);
    92→								}
    93→								await notifySignup(
    94→									config.slackWebhookUrl,
    95→									{ name: user.name, email: user.email },
    96→									githubHandle,
    97→								);
    98→							}
    99→						} catch (err) {
   100→							logger.error(
   101→								"Failed to create default organization for user {userId}: {error}",
   102→								{ userId: user.id, error: err },
   103→							);
   104→						}
   105→					},
   106→				},
   107→			},
   108→		},
   109→	});
   110→}
   111→
   112→export type Auth = ReturnType<typeof createAuth>;
   113→export type Session = Auth["$Infer"]["Session"];
