   139→				path: url.pathname,
   140→				status: response.status,
   141→				body,
   142→			});
   143→		}
   144→		for (const [key, value] of Object.entries(cors)) {
   145→			response.headers.set(key, value);
   146→		}
   147→		return response;
   148→	}
   149→
   150→	// Static file serving (production: frontend assets)
   151→	const filePath = join(STATIC_DIR, url.pathname);
   152→	const file = Bun.file(filePath);
   153→	if (await file.exists()) {
   154→		return new Response(file);
   155→	}
   156→
   157→	// SPA fallback: serve index.html for non-API routes
   158→	const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
   159→	if (await indexFile.exists()) {
