     9→import { buildCommand } from "@stricli/core";
    10→import type { BatchUploadItem } from "../lib/batch-upload.js";
    11→import { renderBatchSummary, runBatchUpload } from "../lib/batch-upload-ui.js";
    12→import { classifySession } from "../lib/classifier.js";
    13→import { loadCredentials } from "../lib/credentials.js";
    14→import { loadFailedUploads } from "../lib/failed-uploads.js";
    15→import { getGitInfo } from "../lib/git-info.js";
    16→import { getProjectOrgId } from "../lib/project-config.js";
    17→import { scanAndGroupProjects } from "../lib/project-grouping.js";
    18→import { resolveSession } from "../lib/session-resolver.js";
    19→import {
    20→	DEFAULT_ENDPOINT,
