    22→	type SessionTag,
    23→} from "../lib/types.js";
    24→import { type UploadConfig, uploadSession } from "../lib/uploader.js";
    25→
    26→interface UploadFlags {
    27→	tag?: SessionTag;
    28→	endpoint: string;
    29→	classify: boolean;
    30→	dryRun: boolean;
    31→	org?: string;
    32→	retry: boolean;
    33→	concurrency: number;
    34→}
    35→
    36→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
    37→	const credentials = loadCredentials();
    38→	if (!credentials && !flags.dryRun) {
    39→		p.log.error("Not authenticated. Run `rudel login` first.");
    40→		process.exitCode = 1;
    41→		return;
    42→	}
    43→
    44→	p.intro("rudel upload");
    45→
    46→	const spin = p.spinner();
    47→	spin.start("Scanning projects...");
    48→
    49→	const { projects: allProjects, groups } = await scanAndGroupProjects();
    50→
    51→	spin.stop(`Found ${allProjects.length} project(s)`);
    52→
    53→	if (allProjects.length === 0) {
    54→		p.log.warn("No projects with sessions found.");
    55→		p.outro("Nothing to upload.");
    56→		return;
    57→	}
    58→
    59→	const options: Array<{
    60→		value: ScannedProject;
    61→		label: string;
    62→		hint: string;
    63→	}> = [];
    64→	const preSelected: ScannedProject[] = [];
    65→
    66→	for (const group of groups) {
    67→		for (const proj of group.projects) {
    68→			options.push({
    69→				value: proj,
    70→				label: `[${getAdapterName(proj.source)}] ${proj.displayPath}`,
    71→				hint: sessionCountHint(proj.sessionCount),
    72→			});
    73→			if (group.containsCwd) {
    74→				preSelected.push(proj);
    75→			}
    76→		}
    77→	}
    78→
    79→	const selected = await p.multiselect({
    80→		message: "Select projects to upload",
    81→		options,
    82→		initialValues: preSelected,
    83→		required: true,
    84→	});
    85→
    86→	if (p.isCancel(selected)) {
    87→		p.cancel("Upload cancelled.");
    88→		return;
    89→	}
    90→
    91→	const totalSessions = selected.reduce(
    92→		(sum, proj) => sum + proj.sessionCount,
    93→		0,
    94→	);
    95→	p.log.info(
    96→		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
    97→	);
    98→
    99→	const uploadConfig: UploadConfig = {
   100→		endpoint: flags.endpoint,
   101→		token: credentials?.token ?? "",
   102→	};
   103→
   104→	// Flatten all sessions with their project context for concurrent upload
   105→	const work: Array<{
   106→		session: (typeof selected)[number]["sessions"][number];
   107→		project: ScannedProject;
   108→		adapter: ReturnType<typeof getAdapter>;
   109→		gitInfo: Awaited<ReturnType<typeof getGitInfo>>;
   110→		organizationId: string | undefined;
   111→	}> = [];
   112→
   113→	for (const project of selected) {
   114→		const adapter = getAdapter(project.source);
   115→		const gitInfo = await getGitInfo(project.projectPath);
   116→		const organizationId =
   117→			flags.org ?? (await getProjectOrgId(project.projectPath));
   118→		for (const session of project.sessions) {
   119→			work.push({ session, project, adapter, gitInfo, organizationId });
   120→		}
   121→	}
   122→
   123→	type InteractiveItem = BatchUploadItem & {
   124→		session: (typeof work)[number]["session"];
   125→		adapter: (typeof work)[number]["adapter"];
   126→		gitInfo: (typeof work)[number]["gitInfo"];
   127→	};
   128→
   129→	const items: InteractiveItem[] = work.map((w) => ({
   130→		sessionId: w.session.sessionId,
   131→		label: `${w.project.displayPath}/${w.session.sessionId}`,
   132→		transcriptPath: w.session.transcriptPath,
   133→		projectPath: w.session.projectPath,
   134→		source: w.project.source,
   135→		organizationId: w.organizationId,
   136→		session: w.session,
   137→		adapter: w.adapter,
   138→		gitInfo: w.gitInfo,
   139→	}));
   140→
   141→	const summary = await runBatchUpload({
   142→		items,
   143→		label: "Uploading sessions...",
   144→		concurrency: flags.concurrency,
   145→		upload: async (item, onRetry) => {
   146→			const request = await item.adapter.buildUploadRequest(item.session, {
   147→				tag: flags.tag,
   148→				gitInfo: item.gitInfo,
   149→				organizationId: item.organizationId,
   150→			});
   151→
   152→			if (!flags.tag && flags.classify) {
   153→				const classified = await classifySession(request.content);
   154→				if (classified) {
   155→					(request as { tag?: string }).tag = classified;
   156→				}
   157→			}
   158→
   159→			if (flags.dryRun) {
   160→				return { success: true };
   161→			}
   162→
   163→			return uploadSession(request, { ...uploadConfig, onRetry });
   164→		},
   165→	});
   166→
   167→	renderBatchSummary(summary, { showRetryHint: summary.failed > 0 });
   168→
   169→	if (flags.dryRun) {
   170→		p.outro("Dry run complete — no sessions were uploaded.");
   171→	} else {
   172→		p.outro("Done!");
   173→	}
   174→
   175→	if (summary.failed > 0) {
   176→		process.exitCode = 1;
   177→	}
   178→}
   179→
   180→function getAdapterName(source: Source): string {
   181→	return getAdapter(source).name;
   182→}
   183→
   184→function sessionCountHint(count: number): string {
   185→	return `${count} session${count !== 1 ? "s" : ""}`;
   186→}
   187→
